def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.3:
            score += (1 - ratio) ** 3 * 15
            for k in range(1, 5):
                score += np.sin(ratio * k * np.pi) * 2
        elif 0.3 <= ratio <= 0.7:
            score += np.log1p(ratio) * 8
            for m in range(1, 4):
                score += ((-1) ** m) * (ratio ** m) * 3
        elif 0.7 < ratio <= 1:
            score += (1 / (1 + np.exp(-10 * (ratio - 0.85)))) * 20
            for n in range(1, int(capacity) + 1):
                if capacity % n == 0 and n % 2 == 0:
                    score += n * 0.5
        else:
            penalty = 0
            int_ratio = int(ratio)
            for j in range(1, int_ratio + 1):
                if int_ratio % j == 0:
                    penalty += j
            if int_ratio > 0:
                penalty /= int_ratio
            score = penalty * 10 + (ratio - 1) * 25
            if ratio > 1.5:
                for p in range(1, 4):
                    score += np.tanh(ratio / (p + 0.5)) * 5
        if capacity % 3 == 0:
            score *= 0.9
        if int(capacity) % 5 == 0 and ratio < 1:
            score *= 1.1
        priorities[i] = score
    min_priority = np.min(priorities[np.isfinite(priorities)])
    priorities = np.where(np.isfinite(priorities), priorities, min_priority + 200)
    return priorities
